<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; }

  body {
    font-family: system-ui, -apple-system, sans-serif;
    max-width: 720px;
    margin: 2rem auto;
    padding: 0 1rem;
    color: #1a1a1a;
    background: #f8f9fa;
  }

  h1 { font-size: 1.5rem; margin-bottom: 1.5rem; }
  h2 { font-size: 1.15rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }

  /* Form */
  .entry-form {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    display: grid;
    gap: 0.75rem;
  }

  .entry-form label {
    font-weight: 600;
    font-size: 0.9rem;
    display: block;
    margin-bottom: 0.2rem;
  }

  .entry-form input,
  .entry-form select {
    width: 100%;
    padding: 0.5rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.95rem;
  }

  .form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.75rem;
  }

  #add-expense {
    background: #2f80ed;
    color: #fff;
    border: none;
    padding: 0.6rem 1.2rem;
    border-radius: 4px;
    font-size: 0.95rem;
    cursor: pointer;
    margin-top: 0.25rem;
  }

  #add-expense:hover { background: #1a68d1; }

  #form-error {
    color: #c0392b;
    font-size: 0.9rem;
    min-height: 1.2em;
    margin-top: -0.5rem;
  }

  /* Filters */
  .filters-bar {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem 1.25rem;
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    gap: 0.75rem;
    align-items: end;
  }

  .filters-bar label {
    font-weight: 600;
    font-size: 0.85rem;
    display: block;
    margin-bottom: 0.2rem;
  }

  .filters-bar select,
  .filters-bar input[type="date"] {
    width: 100%;
    padding: 0.45rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
  }

  /* Summary */
  .summary-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-top: 1.25rem;
    padding: 0.75rem 1rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
  }

  .summary-bar .total-label { font-weight: 600; }
  #total { font-size: 1.3rem; font-weight: 700; color: #2f80ed; }

  .cat-totals { display: flex; gap: 1rem; flex-wrap: wrap; }
  .cat-total { font-size: 0.9rem; }
  .cat-total strong { margin-right: 0.25rem; }

  /* Expense list */
  #expense-list {
    margin-top: 1rem;
    list-style: none;
    padding: 0;
  }

  .expense {
    display: grid;
    grid-template-columns: auto 1fr auto auto auto;
    align-items: center;
    gap: 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.6rem 1rem;
    margin-bottom: 0.4rem;
    font-size: 0.9rem;
  }

  .expense .exp-cat {
    text-transform: capitalize;
    font-weight: 600;
  }

  .expense .exp-date { color: #555; white-space: nowrap; }
  .expense .exp-note { color: #777; font-style: italic; overflow: hidden; text-overflow: ellipsis; max-width: 140px; }
  .expense .exp-amount { font-weight: 600; white-space: nowrap; }

  .exp-del {
    background: none;
    border: 1px solid #e74c3c;
    color: #e74c3c;
    border-radius: 4px;
    padding: 0.2rem 0.55rem;
    cursor: pointer;
    font-size: 0.85rem;
    line-height: 1;
  }

  .exp-del:hover { background: #e74c3c; color: #fff; }

  .empty-msg {
    text-align: center;
    color: #999;
    padding: 2rem 0;
    font-size: 0.95rem;
  }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<form id="entry-form" class="entry-form">
  <div class="form-row">
    <div>
      <label for="amount">Amount ($)</label>
      <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
    </div>
    <div>
      <label for="category">Category</label>
      <select id="category">
        <option value="">— select —</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
  </div>
  <div class="form-row">
    <div>
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div>
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shop">
    </div>
  </div>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<!-- Filters -->
<h2>Filters</h2>
<div class="filters-bar">
  <div>
    <label for="filter-category">Category</label>
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </div>
  <div>
    <label for="filter-from">From date</label>
    <input type="date" id="filter-from">
  </div>
  <div>
    <label for="filter-to">To date</label>
    <input type="date" id="filter-to">
  </div>
</div>

<!-- Summary -->
<div class="summary-bar">
  <div>
    <span class="total-label">Total: </span><span id="total">0.00</span>
  </div>
  <div class="cat-totals" id="cat-totals"></div>
</div>

<!-- Expense List -->
<h2>Expenses</h2>
<ul id="expense-list"></ul>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "expense_tracker_data";
  var CATEGORIES = ["groceries", "transport", "bills", "fun"];

  // --- State ---
  var expenses = [];

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) expenses = JSON.parse(raw);
    } catch (_) { expenses = []; }
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // --- DOM refs ---
  var form = document.getElementById("entry-form");
  var amountInput = document.getElementById("amount");
  var categorySelect = document.getElementById("category");
  var dateInput = document.getElementById("date");
  var noteInput = document.getElementById("note");
  var addBtn = document.getElementById("add-expense");
  var formError = document.getElementById("form-error");

  var filterCategory = document.getElementById("filter-category");
  var filterFrom = document.getElementById("filter-from");
  var filterTo = document.getElementById("filter-to");

  var totalEl = document.getElementById("total");
  var catTotalsEl = document.getElementById("cat-totals");
  var expenseList = document.getElementById("expense-list");

  // --- Helpers ---
  function formatMoney(n) {
    return n.toFixed(2);
  }

  function showError(msg) {
    formError.textContent = msg;
  }

  function clearError() {
    formError.textContent = "";
  }

  function getFilteredExpenses() {
    var catFilter = filterCategory.value;
    var fromVal = filterFrom.value;
    var toVal = filterTo.value;

    return expenses.filter(function (e) {
      if (catFilter !== "all" && e.category !== catFilter) return false;
      if (fromVal && e.date < fromVal) return false;
      if (toVal && e.date > toVal) return false;
      return true;
    });
  }

  // --- Render ---
  function render() {
    var visible = getFilteredExpenses();

    // Total
    var sum = 0;
    for (var i = 0; i < visible.length; i++) {
      sum += visible[i].amount;
    }
    totalEl.textContent = formatMoney(sum);

    // Per-category totals
    catTotalsEl.innerHTML = "";
    CATEGORIES.forEach(function (cat) {
      var catSum = 0;
      for (var j = 0; j < visible.length; j++) {
        if (visible[j].category === cat) catSum += visible[j].amount;
      }
      var div = document.createElement("div");
      div.className = "cat-total";
      div.setAttribute("data-cat", cat);
      div.innerHTML = '<strong>' + cat.charAt(0).toUpperCase() + cat.slice(1) + ':</strong> ' + formatMoney(catSum);
      catTotalsEl.appendChild(div);
    });

    // Expense list (newest first — already stored newest-first, but ensure sort)
    expenseList.innerHTML = "";
    if (visible.length === 0) {
      var li = document.createElement("li");
      li.className = "empty-msg";
      li.textContent = expenses.length === 0 ? "No expenses yet. Add one above!" : "No expenses match the current filters.";
      expenseList.appendChild(li);
      return;
    }

    // Sort visible by date descending, then by insertion order (reverse of stored)
    var sorted = visible.slice().sort(function (a, b) {
      if (b.date !== a.date) return b.date < a.date ? -1 : 1;
      return b.id - a.id;
    });

    for (var k = 0; k < sorted.length; k++) {
      var e = sorted[k];
      var li = document.createElement("li");
      li.className = "expense";
      li.setAttribute("data-id", e.id);

      var catSpan = document.createElement("span");
      catSpan.className = "exp-cat";
      catSpan.textContent = e.category.charAt(0).toUpperCase() + e.category.slice(1);

      var dateSpan = document.createElement("span");
      dateSpan.className = "exp-date";
      dateSpan.textContent = e.date;

      var noteSpan = document.createElement("span");
      noteSpan.className = "exp-note";
      noteSpan.textContent = e.note || "";
      if (!e.note) noteSpan.style.visibility = "hidden";

      var amtSpan = document.createElement("span");
      amtSpan.className = "exp-amount";
      amtSpan.textContent = "$" + formatMoney(e.amount);

      var delBtn = document.createElement("button");
      delBtn.className = "exp-del";
      delBtn.textContent = "✕";
      delBtn.title = "Delete expense";
      (function (id) {
        delBtn.addEventListener("click", function () {
          expenses = expenses.filter(function (x) { return x.id !== id; });
          save();
          render();
        });
      })(e.id);

      li.appendChild(catSpan);
      li.appendChild(dateSpan);
      li.appendChild(noteSpan);
      li.appendChild(amtSpan);
      li.appendChild(delBtn);
      expenseList.appendChild(li);
    }
  }

  // --- Form submission ---
  form.addEventListener("submit", function (e) {
    e.preventDefault();
    clearError();

    var amountVal = amountInput.value;
    var catVal = categorySelect.value;
    var dateVal = dateInput.value;
    var noteVal = noteInput.value.trim();

    // Validate amount
    if (amountVal === "" || amountVal == null) {
      showError("Please enter an amount.");
      return;
    }
    var numAmount = parseFloat(amountVal);
    if (isNaN(numAmount)) {
      showError("Amount must be a valid number.");
      return;
    }
    if (numAmount <= 0) {
      showError("Amount must be greater than zero.");
      return;
    }

    // Validate date
    if (!dateVal || dateVal === "") {
      showError("Please select a date.");
      return;
    }

    // Validate category
    if (!catVal) {
      showError("Please select a category.");
      return;
    }

    // All valid — add expense
    var id = Date.now() + Math.floor(Math.random() * 1000);
    expenses.push({
      id: id,
      amount: numAmount,
      category: catVal,
      date: dateVal,
      note: noteVal
    });

    save();
    render();

    // Reset form (clear amount and other fields)
    amountInput.value = "";
    categorySelect.value = "";
    dateInput.value = "";
    noteInput.value = "";
  });

  // --- Filter change handlers ---
  filterCategory.addEventListener("change", render);
  filterFrom.addEventListener("change", render);
  filterTo.addEventListener("change", render);

  // --- Init ---
  load();
  render();
})();
</script>

</body>
</html>
